// Python Solution


class Trie:



    def __init__(self):



        self.root = TrieNode()





    def insert(self, word):



        current = self.root



        for ch in word:



            index = ord(ch) - ord('a')



            if not current.children[index]:



                current.children[index] = TrieNode()



                current.children[index].parent = current





            current = current.children[index]



            current.count += 1





    def delete(self, word):



        current = self.root



        for ch in word:



            index = ord(ch) - ord('a')



            if not current.children[index]:



                return





            current = current.children[index]



            current.count -= 1



        current.count = 0



    def autoComplete(self, word):



        current = self.root



        ans = []



        for ch in word:



            index = ord(ch) - ord('a')



            if not current.children[index]:



                return ans





            current = current.children[index]





        self._dfs(current, word, ans)



        return ans





    def _dfs(self, node, word, ans):



        if node.count > 0:



            ans.append(word)





        for i in range(26):



            if node.children[i]:



                self._dfs(node.children[i], word + chr(i + ord('a')), ans)





    def search(self, word):



        current = self.root



        for ch in word:



            index = ord(ch) - ord('a')



            if not current.children[index]:



                return False





            current = current.children[index]



        return True







