// C++ Solution


class TrieNode {



    public:



    int children[26];



    int count;



    TrieNode* parent;



    TrieNode() {



        count = 0;



        for(int i = 0; i < 26; i++) children[i] = nullptr;



    }



};



class Trie {



    public:



    TrieNode* root;



    void insert(string word) {



        TrieNode* current = root;



        for(char ch : word) {



            int index = ch - 'a';



            if(current->children[index] == nullptr) {



                current->children[index] = new TrieNode();



                current->children[index]->parent = current;



            }



            current = current->children[index];



            current->count++;

        }



    }



    void delete(string word) {



        TrieNode* current = root;



        for(char ch : word) {



            int index = ch - 'a';



            if(current->children[index] == nullptr) {



                return;



            }



            current = current->children[index];



            current->count--;

        }



        current->count = 0;

    }



    vector<int> autoComplete(string word) {



        TrieNode* current = root;



        vector<int> ans;



        for(char ch : word) {



            int index = ch - 'a';



            if(current->children[index] == nullptr) {



                return ans;



            }



            current = current->children[index];

        }



        this->_dfs(current, word, ans);



        return ans;

    }



    void _dfs(TrieNode* node, string word, vector<int>& ans) {



        if(node->count > 0) {



            ans.push_back(word.size());



        }



        for(int i = 0; i < 26; i++) {



            if(node->children[i] != nullptr) {



                this->_dfs(node->children[i], word + string(1, 'a' + i), ans);



            }

        }

    }



    bool search(string word) {



        TrieNode* current = root;



        for(char ch : word) {



            int index = ch - 'a';



            if(current->children[index] == nullptr) {



                return false;



            }



            current = current->children[index];

        }



        return true;

    }



};



int main() {



    Trie trie;



    int q;



    cin >> q;



    while(q--) {



        int action;



        string word;



        cin >> action >> word;



        if(action == 0) {



            trie.delete(word);



        } else if(action == 2) {



            cout << (trie.search(word) ? "1" : "0") << '
';



        } else if(action == 1) {



            cout << trie.autoComplete(word).size() << '
';



        } else if(action == -1) {



            break;



        }



    }



    return 0;

}
